do $block$
declare
  admin_count integer;
begin
  select count(*) into admin_count
  from public.user_roles ur
  join public.roles r on r.id = ur.role_id
  where r.code = 'administrator';

  if admin_count <> 1 then
    raise exception
      'Expected exactly one administrator, found %; reviews were not imported.',
      admin_count;
  end if;
end
$block$;

insert into public.validation_campaigns (
  id, name, description, owner_id, status
)
select
  md5('cap-college:validation-campaign:2026-07-23')::uuid,
  'Validation intégrale Français 6e — 23 juillet 2026',
  'Import des 590 évaluations A/B/C/D et commentaires réalisés en conditions réelles.',
  ur.user_id,
  'active'::public.campaign_status
from public.user_roles ur
join public.roles r on r.id = ur.role_id
where r.code = 'administrator'
on conflict (id) do update
set name = excluded.name,
    description = excluded.description,
    owner_id = excluded.owner_id;

with review_rows as (
  select item
  from public._cap_college_review_import_payload p,
       jsonb_array_elements(p.payload) as review(item)
), resolved as (
  select
    row.item,
    q.id as question_id,
    qv.id as question_version_id,
    vc.id as campaign_id,
    vc.owner_id as reviewer_id,
    case
      when row.item ->> 'grade' = 'A'
       and btrim(coalesce(row.item ->> 'comment', '')) = ''
        then 'approved'::public.review_status
      when row.item ->> 'grade' = 'D'
        then 'rejected'::public.review_status
      else 'changes_requested'::public.review_status
    end as mapped_status
  from review_rows row
  join public.questions q
    on q.legacy_id = (row.item ->> 'question_id')::bigint
  join public.question_versions qv
    on qv.question_id = q.id
   and qv.version_number = q.current_version_number
  cross join public.validation_campaigns vc
  where vc.id = md5('cap-college:validation-campaign:2026-07-23')::uuid
)
insert into public.question_reviews (
  id,
  campaign_id,
  question_version_id,
  reviewer_id,
  status,
  grade,
  comment,
  reviewed_at
)
select
  md5('cap-college:review:2026-07-23:' || (r.item ->> 'question_id'))::uuid,
  r.campaign_id,
  r.question_version_id,
  r.reviewer_id,
  r.mapped_status,
  nullif(r.item ->> 'grade', '')::char(1),
  nullif(btrim(r.item ->> 'comment'), ''),
  coalesce(
    nullif(r.item ->> 'reviewed_at', '')::timestamptz,
    statement_timestamp()
  )
from resolved r
on conflict (id) do update
set question_version_id = excluded.question_version_id,
    reviewer_id = excluded.reviewer_id,
    status = excluded.status,
    grade = excluded.grade,
    comment = excluded.comment,
    reviewed_at = excluded.reviewed_at;

with review_rows as (
  select item
  from public._cap_college_review_import_payload p,
       jsonb_array_elements(p.payload) as review(item)
), commented as (
  select
    row.item,
    q.id as question_id,
    qv.id as question_version_id,
    vc.id as campaign_id,
    vc.owner_id as reporter_id
  from review_rows row
  join public.questions q
    on q.legacy_id = (row.item ->> 'question_id')::bigint
  join public.question_versions qv
    on qv.question_id = q.id
   and qv.version_number = q.current_version_number
  cross join public.validation_campaigns vc
  where vc.id = md5('cap-college:validation-campaign:2026-07-23')::uuid
    and btrim(coalesce(row.item ->> 'comment', '')) <> ''
)
insert into public.question_flags (
  id,
  question_id,
  question_version_id,
  campaign_id,
  reported_by,
  comment,
  status,
  reported_at
)
select
  md5('cap-college:flag:2026-07-23:' || (c.item ->> 'question_id'))::uuid,
  c.question_id,
  c.question_version_id,
  c.campaign_id,
  c.reporter_id,
  c.item ->> 'comment',
  'open'::public.flag_status,
  coalesce(
    nullif(c.item ->> 'reviewed_at', '')::timestamptz,
    statement_timestamp()
  )
from commented c
on conflict (id) do update
set question_version_id = excluded.question_version_id,
    comment = excluded.comment,
    status = 'open',
    resolved_by = null,
    resolved_at = null,
    resolution_comment = null;

with review_rows as (
  select item
  from public._cap_college_review_import_payload p,
       jsonb_array_elements(p.payload) as review(item)
), mapped as (
  select
    q.id as question_id,
    qv.id as question_version_id,
    case
      when row.item ->> 'grade' = 'A'
       and btrim(coalesce(row.item ->> 'comment', '')) = ''
        then 'approved'::public.review_status
      when row.item ->> 'grade' = 'D'
        then 'rejected'::public.review_status
      else 'changes_requested'::public.review_status
    end as review_status,
    case
      when row.item ->> 'grade' = 'A'
       and btrim(coalesce(row.item ->> 'comment', '')) = ''
        then 'published'::public.question_status
      else 'in_review'::public.question_status
    end as question_status
  from review_rows row
  join public.questions q
    on q.legacy_id = (row.item ->> 'question_id')::bigint
  join public.question_versions qv
    on qv.question_id = q.id
   and qv.version_number = q.current_version_number
)
update public.question_versions qv
set review_status = mapped.review_status,
    published_at = case
      when mapped.question_status = 'published'
        then coalesce(qv.published_at, statement_timestamp())
      else null
    end
from mapped
where qv.id = mapped.question_version_id;

with review_rows as (
  select item
  from public._cap_college_review_import_payload p,
       jsonb_array_elements(p.payload) as review(item)
), mapped as (
  select
    q.id as question_id,
    case
      when row.item ->> 'grade' = 'A'
       and btrim(coalesce(row.item ->> 'comment', '')) = ''
        then 'published'::public.question_status
      else 'in_review'::public.question_status
    end as question_status
  from review_rows row
  join public.questions q
    on q.legacy_id = (row.item ->> 'question_id')::bigint
)
update public.questions q
set status = mapped.question_status
from mapped
where q.id = mapped.question_id;

do $block$
declare
  campaign_review_count integer;
  campaign_flag_count integer;
  published_count integer;
  in_review_count integer;
begin
  select count(*) into campaign_review_count
  from public.question_reviews
  where campaign_id = md5('cap-college:validation-campaign:2026-07-23')::uuid;

  select count(*) into campaign_flag_count
  from public.question_flags
  where campaign_id = md5('cap-college:validation-campaign:2026-07-23')::uuid;

  select count(*) into published_count
  from public.questions
  where legacy_id between 1 and 590
    and status = 'published';

  select count(*) into in_review_count
  from public.questions
  where legacy_id between 1 and 590
    and status = 'in_review';

  if campaign_review_count <> 590 then
    raise exception 'Expected 590 reviews, found %', campaign_review_count;
  end if;
  if campaign_flag_count <> 38 then
    raise exception 'Expected 38 flags, found %', campaign_flag_count;
  end if;
  if published_count <> 531 then
    raise exception 'Expected 531 published questions, found %', published_count;
  end if;
  if in_review_count <> 59 then
    raise exception 'Expected 59 questions in review, found %', in_review_count;
  end if;
end
$block$;

commit;